    private static string GetBadgeClass(ApprovalStatus status)
    {
        return status switch
        {
            ApprovalStatus.Approved => "text-bg-success",
            ApprovalStatus.PendingReview => "text-bg-warning",
            ApprovalStatus.Rejected => "text-bg-danger",
            _ => "text-bg-secondary"
        };
    }

